(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,84116,e=>{"use strict";var n=e.i(43476);let r="NeXify AI by NeXify – chat it. Automate it.",i="Pascal Courbois",t="Graaf van Loonstraat 1E, 5921 JA Venlo, Niederlande",a="mail@nexifyai.cloud",s="+31 6 133 188 56",d={impressum:{slug:"impressum",title:"Impressum",intro:"Anbieterkennzeichnung und Kontaktinformationen von NeXify AI by NeXify – chat it. Automate it.",updated:"Juni 2026",sections:[{heading:"Angaben zum Unternehmen",paragraphs:[r,`Eenmanszaak (Einzelunternehmen nach niederl\xe4ndischem Recht), Inhaber: ${i}`,t]},{heading:"Kontakt",paragraphs:[`E-Mail: ${a}`,`Telefon: ${s}`,"Web: nexifyai.cloud"]},{heading:"Register- und Steuerangaben",paragraphs:["Kamer van Koophandel (KvK): 90483944","BTW-Identifikationsnummer (Umsatzsteuer-ID): NL865786276B01","Tätigkeitsbereich: IT-Beratung, AI-gestützte Automatisierung, Softwareentwicklung, Webentwicklung und E-Commerce-Lösungen."]},{heading:"Vertretung und redaktionelle Verantwortung",paragraphs:[`${i}, Inhaber / Directeur.`,`Verantwortlich f\xfcr redaktionelle Inhalte: ${i}, Anschrift wie oben.`]},{heading:"Aufsicht und anwendbares Recht",paragraphs:["Als in den Niederlanden ansässiges Einzelunternehmen unterliegt NeXify AI dem niederländischen Handels- und Gewerberecht. Zuständige Handelskammer ist die Kamer van Koophandel (KvK).","Für datenschutzrechtliche Belange ist die Autoriteit Persoonsgegevens (Den Haag, Niederlande) die zuständige Aufsichtsbehörde."]},{heading:"B2B-Ausrichtung",paragraphs:["Das Angebot richtet sich ausschließlich an Unternehmer, juristische Personen des öffentlichen Rechts und vergleichbare Organisationen, die in Ausübung ihrer gewerblichen oder selbstständigen beruflichen Tätigkeit handeln. Verträge mit Verbrauchern werden nicht geschlossen."]},{heading:"Haftung für Inhalte",paragraphs:["Die Inhalte dieser Website werden mit größter Sorgfalt erstellt und regelmäßig aktualisiert. Eine Gewähr für Richtigkeit, Vollständigkeit und Aktualität wird nur übernommen, soweit dies ausdrücklich vereinbart oder gesetzlich zwingend vorgeschrieben ist.","Preisangaben auf dieser Website stellen kein bindendes Angebot dar, sondern eine transparente Orientierung. Verbindlich sind ausschließlich individuell erstellte und schriftlich bestätigte Angebote."]},{heading:"Haftung für Links",paragraphs:["Verlinkte externe Angebote unterliegen der Verantwortung ihrer jeweiligen Betreiber. Zum Zeitpunkt der Verlinkung waren keine Rechtsverstöße erkennbar. Rechtswidrige Inhalte werden nach Kenntnis und angemessener Prüfung entfernt oder die Verlinkung beendet."]},{heading:"Urheberrecht",paragraphs:["Sämtliche Inhalte, Grafiken, Logos und Gestaltungselemente dieser Website unterliegen dem Urheberrecht. Jede Verwertung außerhalb der gesetzlichen Schranken bedarf der vorherigen schriftlichen Zustimmung. Marken- und Produktnamen Dritter sind Eigentum ihrer jeweiligen Inhaber."]},{heading:"Online-Streitbeilegung",paragraphs:["Da NeXify AI ausschließlich B2B-Leistungen anbietet, besteht keine Verpflichtung und keine Teilnahme an Verbraucherschlichtungsverfahren. Anfragen zu Verträgen oder Leistungen können direkt an die oben genannte E-Mail-Adresse gerichtet werden."]}]},datenschutz:{slug:"datenschutz",title:"Datenschutzerklärung",intro:"Umfassende Informationen zur Verarbeitung personenbezogener Daten auf dieser Website, im KI-Chat und im Rahmen geschäftlicher Anfragen gemäß DSGVO / AVG.",updated:"Juni 2026",sections:[{heading:"1. Verantwortlicher",paragraphs:[`${r}, ${t}.`,`Inhaber: ${i}. Kontakt: ${a}, ${s}.`]},{heading:"2. Grundsätze der Verarbeitung",paragraphs:["NeXify AI verarbeitet personenbezogene Daten zweckgebunden, verhältnismäßig und nur so lange, wie dies für den jeweiligen Zweck, gesetzliche Pflichten oder die Wahrung berechtigter Interessen erforderlich ist (Art. 5 DSGVO).","Diese Website ist grundsätzlich ohne Nutzerkonto und ohne Marketing-Tracking nutzbar. Nicht notwendige Analyse- oder Werbecookies werden nicht standardmäßig eingesetzt."]},{heading:"3. Hosting, CDN und technische Protokolldaten",paragraphs:["Beim Aufruf der Website können technisch erforderliche Daten verarbeitet werden, insbesondere IP-Adresse, Zeitpunkt, aufgerufene Ressource, Referrer, Browser-/Geräteinformationen und Statuscodes. Dies dient der Auslieferung, Stabilität, Fehleranalyse und dem Schutz vor Missbrauch.","Zur Auslieferung und Absicherung der Website können Content-Delivery- und Schutzdienste (z. B. Cloudflare) sowie Hosting-Infrastruktur (z. B. Vercel oder eigene Server in der EU) eingesetzt werden. Mit den Anbietern bestehen, soweit erforderlich, Auftragsverarbeitungsverträge.","Rechtsgrundlage ist Art. 6 Abs. 1 lit. f DSGVO (berechtigtes Interesse an einem sicheren und funktionsfähigen Webangebot). Protokolle werden auf das notwendige Maß begrenzt und nach Ablauf betrieblicher oder gesetzlicher Erfordernisse gelöscht oder anonymisiert."]},{heading:"4. Kontaktformular und Kommunikation",paragraphs:["Bei einer Anfrage werden die von Ihnen übermittelten Angaben verarbeitet, insbesondere Name, Unternehmen, Kontaktdaten, Projektangaben und Nachricht. Zweck ist die Bearbeitung der Anfrage, vorvertragliche Kommunikation und gegebenenfalls die Durchführung des Vertrags.","Rechtsgrundlagen sind Art. 6 Abs. 1 lit. b DSGVO (vorvertragliche Maßnahmen bzw. Vertragserfüllung) sowie Art. 6 Abs. 1 lit. f DSGVO (berechtigtes Interesse an sachgerechter B2B-Kommunikation). Pflichtangaben sind im Formular gekennzeichnet.","Anfragedaten werden in einer gesicherten Datenbank (Supabase, PostgreSQL, Serverstandort EU) gespeichert."]},{heading:"5. KI-Berater „NeXify AI“ (Live-Chat)",paragraphs:["Auf dieser Website steht ein KI-gestützter Berater („NeXify AI“) zur Verfügung. Bei Nutzung des Chats werden Ihre Chat-Nachrichten sowie eine zufällig erzeugte Sitzungskennung verarbeitet und gespeichert, um den Gesprächsverlauf bereitzustellen, Anfragen zu qualifizieren und auf Wunsch ein Angebot zu erstellen.","Zur Erzeugung der Antworten werden Chat-Inhalte an ein KI-Sprachmodell (Large Language Model) eines spezialisierten Anbieters übermittelt. Übermitteln Sie im Chat bitte keine sensiblen oder besonders schutzbedürftigen Daten. Die Chat-Inhalte werden nicht zur allgemeinen Modellschulung freigegeben, soweit dies nicht ausdrücklich vereinbart und rechtlich zulässig ist.","Geben Sie im Chat freiwillig Name, E-Mail-Adresse und Firma an, um ein Angebot zu erhalten, werden diese Daten zur Erstellung und Zusendung des Angebots sowie für eine angemessene geschäftliche Nachverfolgung (Follow-up-E-Mail) verwendet.","Rechtsgrundlagen: Art. 6 Abs. 1 lit. b DSGVO (vorvertragliche Maßnahmen auf Ihre Anfrage) und Art. 6 Abs. 1 lit. f DSGVO (berechtigtes Interesse an effizienter Erstberatung). Sie sind nicht verpflichtet, den Chat zu nutzen – alle Anliegen können alternativ per E-Mail oder Telefon gestellt werden.","Gedächtnisfunktion: Um wiederkehrende Interessenten und Kunden über mehrere Kontakte hinweg individuell beraten zu können, können zentrale Gesprächsinhalte (z. B. Branche, Projektziele, Präferenzen) in verdichteter Form als Merkposten gespeichert werden. Hierfür wird der spezialisierte Dienst Mem0 (Mem0 AI, USA) eingesetzt; die Übermittlung erfolgt auf Grundlage von EU-Standardvertragsklauseln (Art. 46 Abs. 2 lit. c DSGVO). Rechtsgrundlage der Speicherung ist Art. 6 Abs. 1 lit. f DSGVO (berechtigtes Interesse an personalisierter, effizienter Betreuung). Sie können dieser Speicherung jederzeit formlos widersprechen (mail@nexifyai.cloud); die Merkposten werden dann gelöscht.","Keine automatisierte Entscheidung im Sinne des Art. 22 DSGVO: Der KI-Berater trifft keine Entscheidungen mit Rechtswirkung oder ähnlich erheblicher Beeinträchtigung. Angebote sind unverbindliche Indikationen und werden vor Vertragsschluss stets menschlich geprüft."]},{heading:"6. E-Mail-Versand und Dienstleister",paragraphs:["Für den technischen Versand von Formularbestätigungen, Angeboten und transaktionalen E-Mails wird ein spezialisierter E-Mail-Dienst (Resend) eingesetzt. Dabei werden nur die für Versand, Zustellung und Missbrauchsschutz notwendigen Daten verarbeitet (Empfängeradresse, Inhalt, Zustellstatus).","Eingehende E-Mails an mail@nexifyai.cloud (Postfach bei Hostinger) werden zur effizienten Bearbeitung KI-gestützt vorsortiert (z. B. Erkennung unerwünschter Werbung) und bei geschäftlichen Anfragen automatisiert beantwortet. Sie werden im automatisierten Antwortprozess mit einem KI-System kommunizieren; eine persönliche Bearbeitung durch Pascal Courbois erfolgt jederzeit auf Wunsch und bei allen Anliegen, die menschliche Prüfung erfordern. Rechtsgrundlagen: Art. 6 Abs. 1 lit. b und lit. f DSGVO (effiziente Bearbeitung eingehender Geschäftskommunikation).","Interner CEO-Agent (Fabrik-Empfehlungen): Aus dem Betreff und den ersten Zeilen einer geschäftlichen Anfrage wird intern ein strukturierter Angebotsentwurf (Positionen, Preis-Schätzung, Rückfragen) durch ein KI-System erzeugt und Pascal Courbois zur Freigabe vorgelegt. Es findet KEIN automatischer Angebotsversand statt – die Entscheidung trifft ausschließlich der Mensch (Art. 22 Abs. 1 DSGVO ist damit nicht berührt). Rechtsgrundlage: Art. 6 Abs. 1 lit. f DSGVO (berechtigtes Interesse an schneller, qualitätsgesicherter Angebotsvorbereitung).","Dienstleister werden sorgfältig ausgewählt, vertraglich gebunden (Art. 28 DSGVO) und nur im erforderlichen Umfang eingesetzt. Bei Übermittlungen außerhalb des Europäischen Wirtschaftsraums werden geeignete Garantien (z. B. EU-Standardvertragsklauseln) und zusätzliche Schutzmaßnahmen geprüft."]},{heading:"7. Datenbank und Speicherorte",paragraphs:["Anfragen, Chat-Verläufe, Leads und Angebotsdaten werden in einer PostgreSQL-Datenbank des Anbieters Supabase gespeichert. Der Serverstandort liegt in der Europäischen Union. Zugriffe sind verschlüsselt (TLS) und auf das erforderliche Minimum beschränkt."]},{heading:"8. Geschäftskontakte und B2B-Projekte",paragraphs:["Im Rahmen von Angeboten und Projekten können Ansprechpartner-, Vertrags-, Kommunikations-, Abrechnungs- und Projektdaten verarbeitet werden. Rechtsgrundlagen sind vorvertragliche Maßnahmen, Vertragserfüllung, gesetzliche Pflichten (insbesondere steuerliche Aufbewahrung) sowie berechtigte Interessen an Dokumentation, Qualitätssicherung und Rechtsverteidigung."]},{heading:"9. AI-gestützte Verarbeitung in Projekten",paragraphs:["NeXify AI kann AI-gestützte Werkzeuge für Strukturierung, Entwürfe, Entwicklung, Tests und Dokumentation einsetzen. Personenbezogene oder vertrauliche Daten werden nur übertragen, wenn dies für den vereinbarten Zweck erforderlich, vertraglich zulässig und technisch angemessen abgesichert ist.","AI-Ausgaben werden nicht ungeprüft als fachlich verbindliche Entscheidung behandelt. Weitere Hinweise stehen unter „KI-Hinweise“."]},{heading:"10. Speicherdauer",paragraphs:["Anfrage- und Chatdaten werden grundsätzlich so lange gespeichert, wie dies zur Bearbeitung und für angemessene Anschlusskommunikation erforderlich ist, und anschließend gelöscht oder anonymisiert.","Vertrags- und Abrechnungsdaten werden entsprechend gesetzlicher Aufbewahrungspflichten (in den Niederlanden in der Regel 7 Jahre) gespeichert. Daten können länger aufbewahrt werden, wenn dies zur Geltendmachung, Ausübung oder Verteidigung von Rechtsansprüchen erforderlich ist."]},{heading:"11. Ihre Rechte",bullets:["Auskunft über verarbeitete personenbezogene Daten (Art. 15 DSGVO)","Berichtigung unrichtiger oder unvollständiger Daten (Art. 16 DSGVO)","Löschung, soweit keine vorrangigen Pflichten entgegenstehen (Art. 17 DSGVO)","Einschränkung der Verarbeitung (Art. 18 DSGVO)","Datenübertragbarkeit (Art. 20 DSGVO)","Widerspruch gegen Verarbeitungen auf Grundlage berechtigter Interessen (Art. 21 DSGVO)","Widerruf einer Einwilligung mit Wirkung für die Zukunft (Art. 7 Abs. 3 DSGVO)","Beschwerde bei einer Datenschutzaufsichtsbehörde, insbesondere der Autoriteit Persoonsgegevens (NL) oder der für Sie zuständigen Behörde"]},{heading:"12. Sicherheit und Aktualisierung",paragraphs:["NeXify AI setzt angemessene technische und organisatorische Maßnahmen ein, darunter Transportverschlüsselung (TLS), Zugriffsbeschränkungen, Datensparsamkeit und regelmäßige Aktualisierungen. Kein Internetdienst kann jedoch absolute Sicherheit garantieren.","Diese Erklärung wird angepasst, wenn Prozesse, Dienstleister oder rechtliche Anforderungen dies erfordern. Es gilt die jeweils auf dieser Seite veröffentlichte Fassung."]}]},agb:{slug:"agb",title:"Allgemeine Geschäftsbedingungen (B2B)",intro:"Vertragsgrundlagen für Beratungs-, Entwicklungs-, Design-, Automatisierungs- und Betriebsleistungen von NeXify AI.",updated:"Juni 2026",sections:[{heading:"1. Geltungsbereich und Unternehmerstatus",paragraphs:["Diese Bedingungen gelten für alle Verträge zwischen NeXify AI und Unternehmern, juristischen Personen oder vergleichbaren Organisationen, die in Ausübung ihrer gewerblichen oder selbstständigen beruflichen Tätigkeit handeln. Verträge mit Verbrauchern werden nicht geschlossen.","Abweichende Bedingungen des Auftraggebers gelten nur, wenn NeXify AI ihnen ausdrücklich in Textform zustimmt. Individuelle vertragliche Vereinbarungen haben Vorrang vor diesen Bedingungen."]},{heading:"2. Vertragsschluss und Leistungsumfang",paragraphs:["Angebote sind freibleibend, sofern sie nicht ausdrücklich als verbindlich bezeichnet werden. Dies gilt auch für automatisiert erstellte Angebotsindikationen des KI-Beraters NeXify AI, die stets unverbindliche Orientierungen darstellen. Ein Vertrag entsteht durch Annahme, Auftragsbestätigung oder Beginn der vereinbarten Leistung.","Maßgeblich sind Angebot, Leistungsbeschreibung, vereinbarte Akzeptanzkriterien und dokumentierte Änderungen. Nicht ausdrücklich eingeschlossene Leistungen gelten als Zusatzaufwand."]},{heading:"3. Aufwand, Arbeitstage und Preis",paragraphs:["Der reguläre Tagessatz beträgt 999 Euro netto pro Arbeitstag. Ein Arbeitstag umfasst bis zu acht planbare Fachstunden.","Aufwandsspannen sind Schätzungen auf Grundlage des bekannten Umfangs. Ein verbindlicher Gesamtfestpreis gilt nur, wenn er ausdrücklich vereinbart wurde. Bei geänderten Anforderungen, fehlenden Inhalten, externen Blockern oder zusätzlichen Integrationen wird der Mehrbedarf vor Ausführung angezeigt.","Preise verstehen sich zuzüglich der anwendbaren Umsatzsteuer. Bei grenzüberschreitenden B2B-Leistungen innerhalb der EU kann bei gültiger Umsatzsteuer-ID das Reverse-Charge-Verfahren gelten."]},{heading:"4. Mitwirkung des Auftraggebers",paragraphs:["Der Auftraggeber stellt Inhalte, Zugangsdaten, Freigaben, Ansprechpartner, rechtliche Texte und fachliche Entscheidungen rechtzeitig bereit. Verzögerungen oder Mehraufwand aus fehlender Mitwirkung können Termin und Preis beeinflussen.","Zugangsdaten sind über vereinbarte sichere Wege bereitzustellen. Geheimnisse dürfen nicht unaufgefordert in öffentliche Tickets, Chats oder Repositories eingestellt werden."]},{heading:"5. AI-gestützte Arbeitsweise",paragraphs:["NeXify AI setzt moderne AI-gestützte Entwicklungs-, Analyse- und Prüfwerkzeuge ein. Diese dienen der Beschleunigung und Qualitätssicherung. Die fachliche Verantwortung wird nicht an ein AI-System übertragen.","Soweit der Auftraggeber besondere Vorgaben zur Verarbeitung, Modellwahl, Datenresidenz oder Geheimhaltung hat, müssen diese vor Projektbeginn mitgeteilt und vereinbart werden."]},{heading:"6. Termine und Lieferfristen",paragraphs:["Auf der Website genannte Richtdauern (z. B. „Website in 2–3 Arbeitstagen“) beziehen sich auf reine Umsetzungszeit ab vollständiger Bereitstellung aller erforderlichen Inhalte und Freigaben. Verbindliche Termine bedürfen der ausdrücklichen Vereinbarung.","Höhere Gewalt, Ausfälle von Drittanbietern und vom Auftraggeber zu vertretende Verzögerungen verlängern Fristen angemessen."]},{heading:"7. Abnahme",paragraphs:["Abnahmepflichtige Leistungen werden nach Bereitstellung geprüft. Wesentliche Mängel sind nachvollziehbar und innerhalb der vereinbarten oder angemessenen Frist zu melden. Unwesentliche Abweichungen hindern die Abnahme nicht.","Produktive Nutzung, Veröffentlichung oder ausbleibende Rückmeldung nach angemessener Prüfzeit kann als Abnahme gelten, soweit dies im konkreten Vertrag zulässig und angekündigt ist."]},{heading:"8. Nutzungsrechte und Open Source",paragraphs:["Nach vollständiger Zahlung erhält der Auftraggeber die vereinbarten Nutzungsrechte am individuell erstellten Werk. Vorbestehende Werkzeuge, generische Komponenten, Frameworks, Methoden und Know-how verbleiben bei ihren jeweiligen Rechteinhabern beziehungsweise NeXify AI.","Open-Source-Komponenten und Dienste Dritter unterliegen ihren eigenen Lizenz- und Nutzungsbedingungen. Diese werden nicht durch den Projektvertrag ersetzt."]},{heading:"9. Drittanbieter und laufende Kosten",paragraphs:["Hosting, Domains, Zahlungsanbieter, App-Stores, externe APIs, AI-Modell-Nutzungskosten, Lizenzen, Transaktions- und Nutzungskosten sind nur enthalten, wenn dies ausdrücklich vereinbart ist. Änderungen, Ausfälle oder Einschränkungen von Drittanbietern liegen außerhalb des unmittelbaren Einflusses von NeXify AI."]},{heading:"10. Gewährleistung und Haftung",paragraphs:["NeXify AI behebt reproduzierbare Mängel innerhalb eines angemessenen Zeitraums. Kein Softwareprodukt ist unter allen denkbaren Bedingungen vollständig fehlerfrei; geschuldet ist die vereinbarte Beschaffenheit und fachgerechte Umsetzung.","Unbeschränkte Haftung gilt bei Vorsatz, grober Fahrlässigkeit, Verletzung von Leben, Körper oder Gesundheit sowie zwingender gesetzlicher Haftung. Bei leicht fahrlässiger Verletzung wesentlicher Vertragspflichten ist die Haftung auf den vertragstypisch vorhersehbaren Schaden begrenzt; im Übrigen ist die Haftung für leichte Fahrlässigkeit ausgeschlossen.","Für Datenverlust haftet NeXify AI nur in dem Umfang, der auch bei ordnungsgemäßer, regelmäßiger Datensicherung durch den Auftraggeber eingetreten wäre."]},{heading:"11. Zahlung",paragraphs:["Rechnungen sind innerhalb der ausgewiesenen Frist ohne Abzug zahlbar. Bei größeren Vorhaben können Abschläge, Vorauszahlungen oder Meilensteinzahlungen vereinbart werden.","Bei Zahlungsverzug gelten die gesetzlichen B2B-Folgen einschließlich Verzugszinsen und angemessener Inkasso- beziehungsweise Rechtsverfolgungskosten. NeXify AI kann Leistungen bei erheblichem Zahlungsrückstand nach Ankündigung aussetzen."]},{heading:"12. Vertraulichkeit und Datenschutz",paragraphs:["Beide Parteien behandeln nicht öffentliche Geschäfts- und Projektdaten vertraulich. Die Vertraulichkeit gilt über das Vertragsende hinaus fort.","Soweit NeXify AI personenbezogene Daten im Auftrag verarbeitet, wird eine Vereinbarung zur Auftragsverarbeitung nach Art. 28 DSGVO geschlossen (siehe Seite „AVV“)."]},{heading:"13. Referenznennung",paragraphs:["NeXify AI darf den Auftraggeber nach Projektabschluss mit Name und Logo als Referenz nennen, sofern der Auftraggeber dem nicht widerspricht oder etwas anderes vereinbart wurde. Vertrauliche Projektdetails werden dabei nicht offengelegt."]},{heading:"14. Laufzeit, Kündigung und Projektunterbrechung",paragraphs:["Projektverträge enden mit Erbringung der vereinbarten Leistung. Laufende Leistungen können nach den vereinbarten Fristen gekündigt werden. Das Recht zur außerordentlichen Kündigung bleibt bestehen.","Bei Unterbrechung aus dem Verantwortungsbereich des Auftraggebers werden bereits erbrachte Leistungen abgerechnet; eine spätere Wiederaufnahme kann neu eingeplant werden."]},{heading:"15. Recht, Gerichtsstand und Schlussbestimmungen",paragraphs:["Es gilt niederländisches Recht unter Ausschluss des UN-Kaufrechts und kollisionsrechtlicher Verweisungen, soweit keine zwingenden Vorschriften entgegenstehen. Gerichtsstand für Kaufleute und vergleichbare B2B-Auftraggeber ist der Sitz von NeXify AI, soweit zulässig.","Sollten einzelne Bestimmungen unwirksam sein, bleibt die Wirksamkeit der übrigen Bestimmungen unberührt. Anstelle der unwirksamen Bestimmung gilt die gesetzlich zulässige Regelung, die dem wirtschaftlichen Zweck am nächsten kommt."]}]},"ki-hinweise":{slug:"ki-hinweise",title:"Hinweise zu AI-gestützter Arbeit",intro:"Wie NeXify AI moderne AI-Werkzeuge einsetzt – transparent erklärt, inklusive des KI-Beraters NeXify AI auf dieser Website.",updated:"Juni 2026",sections:[{heading:"AI-gestützt statt AI-abgegeben",paragraphs:["NeXify AI nutzt AI-Werkzeuge für Recherche, Strukturierung, Entwürfe, Entwicklungsunterstützung, Tests, Übersetzungen und Dokumentation. Diese Werkzeuge beschleunigen Arbeitsschritte, ersetzen aber nicht fachliche Verantwortung, Prüfung und Freigabe."]},{heading:"Der NeXify AI Berater auf dieser Website",paragraphs:["NeXify AI ist ein KI-gestützter Beratungs- und Vertriebsassistent. Er beantwortet Fragen zu Leistungen und Preisen, qualifiziert Anfragen und kann auf ausdrücklichen Wunsch ein unverbindliches Angebot erstellen und per E-Mail versenden.","Sie interagieren dabei mit einem automatisierten System, nicht mit einem Menschen. Alle von NeXify AI erstellten Angebote sind unverbindliche Indikationen; verbindliche Angebote werden ausschließlich von Pascal Courbois persönlich geprüft und bestätigt.","Der Assistent verfügt über eine Gedächtnisfunktion: Zentrale Gesprächsinhalte können gespeichert werden, damit Sie bei erneutem Kontakt nicht von vorne beginnen müssen. Zudem können E-Mails an mail@nexifyai.cloud KI-gestützt vorsortiert und beantwortet werden. Details und Widerspruchsmöglichkeiten finden Sie in der Datenschutzerklärung.","Der AI-Berater kann Fehler machen. Bei Unklarheiten oder wichtigen Entscheidungen kontaktieren Sie uns bitte direkt per E-Mail oder Telefon."]},{heading:"Menschliche Kontrolle",bullets:["Ziele, Architektur und fachliche Entscheidungen werden durch einen verantwortlichen Fachmann gesteuert.","AI-Ausgaben werden auf Plausibilität, Sicherheit, Projektkontext und Qualität geprüft.","Rechtliche, steuerliche, medizinische oder andere hochriskante Entscheidungen werden nicht allein auf AI-Ausgaben gestützt.","Produktive Änderungen werden anhand des vereinbarten Risikos getestet und dokumentiert.","Automatisiert erstellte Angebote werden vor Vertragsschluss immer menschlich geprüft."]},{heading:"Daten und Vertraulichkeit",paragraphs:["Vertrauliche oder personenbezogene Daten werden nur im erforderlichen Umfang verarbeitet. Modell-, Hosting- und Datenverarbeitungswege werden passend zum Projekt gewählt. Kundendaten werden nicht bewusst zur allgemeinen Modellschulung freigegeben, sofern dies nicht ausdrücklich vereinbart und rechtlich zulässig ist.","Details zur Datenverarbeitung im Chat finden Sie in der Datenschutzerklärung, Abschnitt „NeXify AI Berater“."]},{heading:"EU AI Act und Transparenz",paragraphs:["NeXify AI verfolgt die Anforderungen der EU-KI-Verordnung (AI Act) und setzt deren Transparenzpflichten um: Nutzer werden darüber informiert, wenn sie mit einem KI-System interagieren, und KI-generierte Angebotsindikationen werden als solche gekennzeichnet.","Bei Kundenprojekten mit KI-Komponenten beraten wir zur Risikoklassifizierung und zu den jeweils geltenden Pflichten."]},{heading:"Grenzen",paragraphs:["AI-Systeme können unvollständige, veraltete oder falsche Ergebnisse erzeugen. NeXify AI begegnet diesem Risiko durch Quellenprüfung, Tests, Review, begrenzte Rechte und nachvollziehbare Arbeitsstände. Eine absolute Fehlerfreiheit kann nicht garantiert werden."]}]},"cookie-richtlinie":{slug:"cookie-richtlinie",title:"Cookie- und Speicherhinweise",intro:"Diese Website ist auf datensparsame Nutzung ohne standardmäßiges Marketing-Tracking ausgelegt.",updated:"Juni 2026",sections:[{heading:"Notwendige Speichertechniken",paragraphs:["Technisch notwendige Cookies oder lokale Speicherungen (localStorage) können eingesetzt werden, um Sicherheit, Formularzustände, Ihre Sprachwahl (Deutsch/Niederländisch), den Zustand des Chat-Assistenten oder elementare Websitefunktionen bereitzustellen. Sie dienen nicht der verhaltensbasierten Werbung."]},{heading:"Konkret eingesetzte Speicherungen",bullets:["nexify-lang (localStorage): speichert Ihre Sprachwahl DE/NL – bis zur Löschung durch Sie.","nova-greeted (localStorage): merkt sich, dass sich der Chat-Assistent bereits vorgestellt hat, um wiederholtes automatisches Öffnen zu vermeiden.","nexify-consent (localStorage): speichert Ihre Auswahl im Cookie-Banner (Kategorien und Zeitpunkt der Entscheidung) – bis zur Löschung oder Änderung durch Sie.","Sitzungskennung des Chats: technische Zuordnung Ihres Gesprächsverlaufs während der Nutzung.","Anmelde-Cookie des Kundenportals (HttpOnly): hält Ihre Sitzung nach dem Login aufrecht; technisch notwendig für den Portalbetrieb."]},{heading:"Ihre Cookie-Einstellungen (Einwilligungs-Manager)",paragraphs:["Beim ersten Besuch dieser Website können Sie über den Cookie-Banner wählen, welche Kategorien Sie zulassen: „Notwendig“ (immer aktiv), „Statistik“ und „Marketing“. Ihre Entscheidung wird ausschließlich lokal in Ihrem Browser gespeichert (nexify-consent) und nicht an Dritte übermittelt.","Die Kategorien Statistik und Marketing sind standardmäßig deaktiviert (Opt-in im Sinne von Art. 6 Abs. 1 lit. a DSGVO bzw. § 25 TDDDG). Solange Sie nicht einwilligen, werden keine entsprechenden Dienste geladen. Derzeit setzt diese Website in beiden Kategorien keine Dienste ein; sie sind für mögliche künftige Erweiterungen vorgesehen und würden vor Aktivierung hier transparent benannt.","Sie können Ihre Auswahl jederzeit mit Wirkung für die Zukunft ändern oder widerrufen: über den Link „Cookie-Einstellungen“ im Seitenfuß jeder Seite."]},{heading:"Keine standardmäßigen Marketing-Cookies",paragraphs:["Ohne gesonderte Ankündigung und Einwilligung werden keine nicht notwendigen Werbe-, Retargeting- oder plattformübergreifenden Tracking-Cookies gesetzt. Wird die Website künftig um solche Dienste erweitert, werden Information und Einwilligungsmechanismus vor Aktivierung angepasst."]},{heading:"Drittdienste",paragraphs:["Zur Auslieferung der Website können CDN- und Schutzdienste (z. B. Cloudflare) technisch notwendige Cookies setzen, die ausschließlich der Sicherheit und Lastverteilung dienen."]},{heading:"Browser-Einstellungen",paragraphs:["Sie können Cookies und lokale Speicherungen über Ihren Browser einsehen, löschen oder blockieren. Bei technisch notwendigen Speicherungen können einzelne Funktionen (z. B. die Sprachwahl) dadurch eingeschränkt sein."]}]},avv:{slug:"avv",title:"Auftragsverarbeitung (AVV)",intro:"Grundsätze für Projekte, in denen NeXify AI personenbezogene Daten im Auftrag eines Kunden verarbeitet (Art. 28 DSGVO).",updated:"Juni 2026",sections:[{heading:"Wann eine AVV erforderlich ist",paragraphs:["Eine Vereinbarung zur Auftragsverarbeitung wird geschlossen, wenn NeXify AI personenbezogene Daten ausschließlich nach dokumentierter Weisung des Kunden verarbeitet und die gesetzlichen Voraussetzungen einer Auftragsverarbeitung vorliegen – etwa beim Betrieb von Web-Apps, Shops oder Automatisierungen mit Kundendaten."]},{heading:"Typische Bestandteile",bullets:["Gegenstand, Dauer, Art und Zweck der Verarbeitung","Kategorien betroffener Personen und personenbezogener Daten","Weisungs- und Unterstützungsprozesse","Vertraulichkeitsverpflichtungen der eingesetzten Personen","Technische und organisatorische Maßnahmen (TOM)","Regeln für Unterauftragsverarbeiter und deren Genehmigung","Unterstützung bei Betroffenenrechten und Datenschutz-Folgenabschätzungen","Löschung, Rückgabe und Nachweise nach Vertragsende","Melde- und Unterstützungspflichten bei Datenschutzvorfällen","Kontroll- und Auditrechte des Verantwortlichen"]},{heading:"Typische Unterauftragsverarbeiter",paragraphs:["Je nach Projekt können insbesondere folgende Kategorien von Unterauftragsverarbeitern eingesetzt werden: Hosting- und Cloud-Infrastruktur (z. B. Vercel, Hetzner, EU-Rechenzentren), Datenbankdienste (z. B. Supabase), E-Mail-Versanddienste (z. B. Resend), CDN- und Sicherheitsdienste (z. B. Cloudflare) sowie – bei AI-Funktionen – Anbieter von KI-Sprachmodellen.","Die konkrete, projektbezogene Liste wird in der jeweiligen AVV dokumentiert und aktuell gehalten."]},{heading:"Technische und organisatorische Maßnahmen",bullets:["Transportverschlüsselung (TLS) für alle Datenübertragungen","Zugriffskontrolle nach dem Least-Privilege-Prinzip","Getrennte Umgebungen für Entwicklung, Test und Produktion","Protokollierung sicherheitsrelevanter Ereignisse","Regelmäßige Updates und Sicherheits-Patches","Datensparsamkeit und Pseudonymisierung, wo möglich"]},{heading:"Projektbezogene Fassung",paragraphs:["Da Datenarten, Systeme, Hosting, Unterauftragnehmer und Risiken vom jeweiligen Projekt abhängen, wird die AVV projektbezogen erstellt oder ergänzt. Eine aktuelle Vorlage und die zugehörigen technischen und organisatorischen Maßnahmen werden im Rahmen der Beauftragung bereitgestellt."]}]},widerruf:{slug:"widerruf",title:"Hinweis zum Widerrufsrecht",intro:"NeXify AI bietet Leistungen ausschließlich im unternehmerischen Geschäftsverkehr (B2B) an.",updated:"Juni 2026",sections:[{heading:"Kein Verbrauchervertrag",paragraphs:["Verträge werden ausschließlich mit Unternehmern, juristischen Personen und vergleichbaren Organisationen geschlossen, die in Ausübung ihrer gewerblichen oder selbstständigen beruflichen Tätigkeit handeln. Das gesetzliche Verbraucherwiderrufsrecht für Fernabsatzverträge findet daher grundsätzlich keine Anwendung.","Mit Anfrage und Beauftragung bestätigt der Auftraggeber, als Unternehmer im Sinne des anwendbaren Rechts zu handeln."]},{heading:"Ausnahmefälle",paragraphs:["Sollte im Ausnahmefall eine Person entgegen dieser Ausrichtung als Verbraucher handeln wollen, muss dies vor Vertragsschluss ausdrücklich offengelegt und gesondert vereinbart werden. In diesem Fall werden die gesetzlichen Informationspflichten und Widerrufsbelehrungen individuell bereitgestellt – oder der Vertragsschluss wird abgelehnt."]},{heading:"Kulanz bei Projektabbruch",paragraphs:["Unabhängig vom fehlenden gesetzlichen Widerrufsrecht gilt: Vor Beginn der Umsetzung kann ein beauftragtes Projekt in Textform kostenfrei storniert werden, sofern noch keine Leistungen erbracht wurden. Bereits erbrachte Konzeptions- oder Umsetzungsleistungen werden anteilig nach Tagessatz abgerechnet."]}]}},g="NeXify AI by NeXify – chat it. Automate it.",o="Pascal Courbois",l="Graaf van Loonstraat 1E, 5921 JA Venlo, Nederland",u="mail@nexifyai.cloud",h="+31 6 133 188 56",c={impressum:{slug:"impressum",title:"Colofon",intro:"Aanbiedersidentificatie en contactgegevens van NeXify AI by NeXify – chat it. Automate it.",updated:"Juni 2026",sections:[{heading:"Bedrijfsgegevens",paragraphs:[g,`Eenmanszaak naar Nederlands recht, eigenaar: ${o}`,l]},{heading:"Contact",paragraphs:[`E-mail: ${u}`,`Telefoon: ${h}`,"Web: nexifyai.cloud"]},{heading:"Registratie- en fiscale gegevens",paragraphs:["Kamer van Koophandel (KvK): 90483944","Btw-identificatienummer: NL865786276B01","Werkterrein: IT-advies, AI-ondersteunde automatisering, softwareontwikkeling, webontwikkeling en e-commerce-oplossingen."]},{heading:"Vertegenwoordiging en redactionele verantwoordelijkheid",paragraphs:[`${o}, eigenaar / directeur.`,`Verantwoordelijk voor redactionele inhoud: ${o}, adres zoals hierboven.`]},{heading:"Toezicht en toepasselijk recht",paragraphs:["Als in Nederland gevestigde eenmanszaak valt NeXify AI onder het Nederlandse handels- en ondernemingsrecht. Bevoegde kamer is de Kamer van Koophandel (KvK).","Voor privacyrechtelijke aangelegenheden is de Autoriteit Persoonsgegevens (Den Haag) de bevoegde toezichthouder."]},{heading:"B2B-oriëntatie",paragraphs:["Het aanbod richt zich uitsluitend op ondernemers, publiekrechtelijke rechtspersonen en vergelijkbare organisaties die handelen in de uitoefening van hun bedrijf of zelfstandig beroep. Overeenkomsten met consumenten worden niet gesloten."]},{heading:"Aansprakelijkheid voor inhoud",paragraphs:["De inhoud van deze website wordt met de grootste zorg samengesteld en regelmatig geactualiseerd. Garantie voor juistheid, volledigheid en actualiteit wordt alleen gegeven voor zover uitdrukkelijk overeengekomen of wettelijk dwingend voorgeschreven.","Prijsvermeldingen op deze website vormen geen bindend aanbod, maar een transparante oriëntatie. Bindend zijn uitsluitend individueel opgestelde en schriftelijk bevestigde offertes."]},{heading:"Aansprakelijkheid voor links",paragraphs:["Gelinkte externe websites vallen onder de verantwoordelijkheid van hun respectieve beheerders. Op het moment van linken waren geen rechtsschendingen herkenbaar. Onrechtmatige inhoud wordt na kennisname en redelijke toetsing verwijderd of de link wordt beëindigd."]},{heading:"Auteursrecht",paragraphs:["Alle inhoud, afbeeldingen, logo's en ontwerpelementen van deze website vallen onder het auteursrecht. Elk gebruik buiten de wettelijke grenzen vereist voorafgaande schriftelijke toestemming. Merk- en productnamen van derden zijn eigendom van hun respectieve houders."]},{heading:"Onlinegeschillenbeslechting",paragraphs:["Aangezien NeXify AI uitsluitend B2B-diensten aanbiedt, bestaat er geen verplichting tot en geen deelname aan consumentengeschillenprocedures. Vragen over overeenkomsten of diensten kunnen rechtstreeks aan het bovengenoemde e-mailadres worden gericht."]}]},datenschutz:{slug:"datenschutz",title:"Privacyverklaring",intro:"Uitgebreide informatie over de verwerking van persoonsgegevens op deze website, in de AI-chat en bij zakelijke aanvragen conform de AVG.",updated:"Juni 2026",sections:[{heading:"1. Verwerkingsverantwoordelijke",paragraphs:[`${g}, ${l}.`,`Eigenaar: ${o}. Contact: ${u}, ${h}.`]},{heading:"2. Uitgangspunten van de verwerking",paragraphs:["NeXify AI verwerkt persoonsgegevens doelgebonden, proportioneel en slechts zolang dit voor het betreffende doel, wettelijke verplichtingen of de behartiging van gerechtvaardigde belangen noodzakelijk is (art. 5 AVG).","Deze website is in principe zonder gebruikersaccount en zonder marketing-tracking te gebruiken. Niet-noodzakelijke analyse- of advertentiecookies worden niet standaard ingezet."]},{heading:"3. Hosting, CDN en technische loggegevens",paragraphs:["Bij het bezoeken van de website kunnen technisch noodzakelijke gegevens worden verwerkt, met name IP-adres, tijdstip, opgevraagde bron, referrer, browser-/apparaatinformatie en statuscodes. Dit dient de levering, stabiliteit, foutanalyse en bescherming tegen misbruik.","Voor de levering en beveiliging van de website kunnen content-delivery- en beschermingsdiensten (bijv. Cloudflare) en hostinginfrastructuur (bijv. Vercel of eigen servers in de EU) worden ingezet. Met de aanbieders bestaan, voor zover vereist, verwerkersovereenkomsten.","Rechtsgrond is art. 6 lid 1 sub f AVG (gerechtvaardigd belang bij een veilig en functioneel webaanbod). Logs worden beperkt tot het noodzakelijke en na afloop van operationele of wettelijke vereisten verwijderd of geanonimiseerd."]},{heading:"4. Contactformulier en communicatie",paragraphs:["Bij een aanvraag worden de door u verstrekte gegevens verwerkt, met name naam, bedrijf, contactgegevens, projectgegevens en bericht. Doel is de behandeling van de aanvraag, precontractuele communicatie en eventueel de uitvoering van de overeenkomst.","Rechtsgronden zijn art. 6 lid 1 sub b AVG (precontractuele maatregelen resp. uitvoering van de overeenkomst) en art. 6 lid 1 sub f AVG (gerechtvaardigd belang bij zorgvuldige B2B-communicatie). Verplichte velden zijn in het formulier gemarkeerd.","Aanvraaggegevens worden opgeslagen in een beveiligde database (Supabase, PostgreSQL, serverlocatie EU)."]},{heading:"5. AI-adviseur „NeXify AI” (livechat)",paragraphs:["Op deze website is een AI-ondersteunde adviseur („NeXify AI”) beschikbaar. Bij gebruik van de chat worden uw chatberichten en een willekeurig gegenereerde sessie-ID verwerkt en opgeslagen om het gespreksverloop aan te bieden, aanvragen te kwalificeren en op verzoek een offerte op te stellen.","Voor het genereren van antwoorden worden chatinhouden doorgegeven aan een AI-taalmodel (Large Language Model) van een gespecialiseerde aanbieder. Deel in de chat a.u.b. geen gevoelige of bijzondere persoonsgegevens. De chatinhouden worden niet vrijgegeven voor algemene modeltraining, tenzij uitdrukkelijk overeengekomen en wettelijk toegestaan.","Geeft u in de chat vrijwillig naam, e-mailadres en bedrijf op om een offerte te ontvangen, dan worden deze gegevens gebruikt voor het opstellen en toezenden van de offerte en voor een passende zakelijke opvolging (follow-up-e-mail).","Rechtsgronden: art. 6 lid 1 sub b AVG (precontractuele maatregelen op uw verzoek) en art. 6 lid 1 sub f AVG (gerechtvaardigd belang bij efficiënt eerste advies). U bent niet verplicht de chat te gebruiken – alle vragen kunnen ook per e-mail of telefoon worden gesteld.","Geheugenfunctie: Om terugkerende geïnteresseerden en klanten over meerdere contactmomenten heen individueel te kunnen adviseren, kunnen kerninhouden van gesprekken (bijv. branche, projectdoelen, voorkeuren) in verdichte vorm als notities worden opgeslagen. Hiervoor wordt de gespecialiseerde dienst Mem0 (Mem0 AI, VS) ingezet; de doorgifte vindt plaats op basis van EU-standaardcontractbepalingen (art. 46 lid 2 sub c AVG). Rechtsgrond voor de opslag is art. 6 lid 1 sub f AVG (gerechtvaardigd belang bij gepersonaliseerde, efficiënte begeleiding). U kunt te allen tijde vormvrij bezwaar maken (mail@nexifyai.cloud); de notities worden dan gewist.","Geen geautomatiseerde besluitvorming in de zin van art. 22 AVG: de AI-adviseur neemt geen besluiten met rechtsgevolgen of vergelijkbaar aanzienlijke gevolgen. Offertes zijn vrijblijvende indicaties en worden vóór het sluiten van een overeenkomst altijd door een mens gecontroleerd."]},{heading:"6. E-mailverzending en dienstverleners",paragraphs:["Voor de technische verzending van formulierbevestigingen, offertes en transactionele e-mails wordt een gespecialiseerde e-maildienst (Resend) ingezet. Daarbij worden alleen de voor verzending, bezorging en misbruikbescherming noodzakelijke gegevens verwerkt (ontvangstadres, inhoud, bezorgstatus).","Inkomende e-mails aan mail@nexifyai.cloud (postvak bij Hostinger) worden voor efficiënte afhandeling AI-ondersteund voorgesorteerd (bijv. herkenning van ongewenste reclame) en bij zakelijke aanvragen geautomatiseerd beantwoord. In het geautomatiseerde antwoordproces communiceert u met een AI-systeem; persoonlijke behandeling door Pascal Courbois vindt te allen tijde op verzoek plaats en bij alle zaken die menselijke beoordeling vereisen. Rechtsgronden: art. 6 lid 1 sub b en sub f AVG (efficiënte afhandeling van inkomende zakelijke communicatie).","Interne CEO-agent (fabriek-aanbevelingen): Uit het onderwerp en de eerste regels van een zakelijke aanvraag wordt intern een gestructureerd offerte-concept (posities, prijs-schatting, vervolgvragen) door een AI-systeem gegenereerd en aan Pascal Courbois ter goedkeuring voorgelegd. Er vindt GEEN automatische offerteverzending plaats – de beslissing wordt uitsluitend door de mens genomen (art. 22 lid 1 AVG is daarmee niet van toepassing). Rechtsgrond: art. 6 lid 1 sub f AVG (gerechtvaardigd belang bij snelle, kwaliteitsgeborgde offertevoorbereiding).","Dienstverleners worden zorgvuldig geselecteerd, contractueel gebonden (art. 28 AVG) en alleen in de vereiste omvang ingezet. Bij doorgiften buiten de Europese Economische Ruimte worden passende waarborgen (bijv. EU-standaardcontractbepalingen) en aanvullende beschermingsmaatregelen getoetst."]},{heading:"7. Database en opslaglocaties",paragraphs:["Aanvragen, chatgesprekken, leads en offertegegevens worden opgeslagen in een PostgreSQL-database van de aanbieder Supabase. De serverlocatie ligt in de Europese Unie. Toegang is versleuteld (TLS) en beperkt tot het noodzakelijke minimum."]},{heading:"8. Zakelijke contacten en B2B-projecten",paragraphs:["In het kader van offertes en projecten kunnen contactpersoon-, contract-, communicatie-, facturatie- en projectgegevens worden verwerkt. Rechtsgronden zijn precontractuele maatregelen, uitvoering van de overeenkomst, wettelijke verplichtingen (met name fiscale bewaarplicht) en gerechtvaardigde belangen bij documentatie, kwaliteitsborging en juridische verdediging."]},{heading:"9. AI-ondersteunde verwerking in projecten",paragraphs:["NeXify AI kan AI-ondersteunde tools inzetten voor structurering, concepten, ontwikkeling, tests en documentatie. Persoonsgegevens of vertrouwelijke gegevens worden alleen doorgegeven als dit voor het overeengekomen doel noodzakelijk, contractueel toegestaan en technisch passend beveiligd is.","AI-uitvoer wordt niet ongecontroleerd als vakinhoudelijk bindende beslissing behandeld. Meer informatie vindt u onder „AI-verklaring”."]},{heading:"10. Bewaartermijnen",paragraphs:["Aanvraag- en chatgegevens worden in principe bewaard zolang dit voor de behandeling en passende vervolgcommunicatie noodzakelijk is, en daarna verwijderd of geanonimiseerd.","Contract- en facturatiegegevens worden conform wettelijke bewaarplichten (in Nederland doorgaans 7 jaar) bewaard. Gegevens kunnen langer worden bewaard indien dit noodzakelijk is voor het instellen, uitoefenen of verdedigen van rechtsvorderingen."]},{heading:"11. Uw rechten",bullets:["Inzage in verwerkte persoonsgegevens (art. 15 AVG)","Rectificatie van onjuiste of onvolledige gegevens (art. 16 AVG)","Verwijdering, voor zover geen voorrang hebbende verplichtingen bestaan (art. 17 AVG)","Beperking van de verwerking (art. 18 AVG)","Overdraagbaarheid van gegevens (art. 20 AVG)","Bezwaar tegen verwerkingen op grond van gerechtvaardigde belangen (art. 21 AVG)","Intrekking van toestemming met werking voor de toekomst (art. 7 lid 3 AVG)","Klacht bij een toezichthoudende autoriteit, met name de Autoriteit Persoonsgegevens (NL)"]},{heading:"12. Beveiliging en actualisering",paragraphs:["NeXify AI hanteert passende technische en organisatorische maatregelen, waaronder transportversleuteling (TLS), toegangsbeperkingen, dataminimalisatie en regelmatige updates. Geen enkele internetdienst kan echter absolute veiligheid garanderen.","Deze verklaring wordt aangepast wanneer processen, dienstverleners of wettelijke vereisten dit vereisen. De op deze pagina gepubliceerde versie is telkens van toepassing."]}]},agb:{slug:"agb",title:"Algemene voorwaarden (B2B)",intro:"Contractuele basis voor advies-, ontwikkelings-, design-, automatiserings- en beheerdiensten van NeXify AI.",updated:"Juni 2026",sections:[{heading:"1. Toepassingsgebied en ondernemersstatus",paragraphs:["Deze voorwaarden gelden voor alle overeenkomsten tussen NeXify AI en ondernemers, rechtspersonen of vergelijkbare organisaties die handelen in de uitoefening van hun bedrijf of zelfstandig beroep. Overeenkomsten met consumenten worden niet gesloten.","Afwijkende voorwaarden van de opdrachtgever gelden alleen indien NeXify AI daar uitdrukkelijk schriftelijk mee instemt. Individuele contractuele afspraken hebben voorrang op deze voorwaarden."]},{heading:"2. Totstandkoming en omvang van de overeenkomst",paragraphs:["Offertes zijn vrijblijvend, tenzij uitdrukkelijk als bindend aangeduid. Dit geldt ook voor automatisch gegenereerde offerte-indicaties van de NeXify AI adviseur, die altijd vrijblijvende oriëntaties vormen. Een overeenkomst komt tot stand door aanvaarding, opdrachtbevestiging of aanvang van de overeengekomen dienst.","Bepalend zijn offerte, dienstbeschrijving, overeengekomen acceptatiecriteria en gedocumenteerde wijzigingen. Niet uitdrukkelijk inbegrepen diensten gelden als meerwerk."]},{heading:"3. Inspanning, werkdagen en prijs",paragraphs:["Het reguliere dagtarief bedraagt € 999 netto per werkdag. Een werkdag omvat maximaal acht planbare vakuren.","Urenramingen zijn schattingen op basis van de bekende omvang. Een bindende totaalprijs geldt alleen indien uitdrukkelijk overeengekomen. Bij gewijzigde eisen, ontbrekende content, externe blokkades of extra integraties wordt het meerwerk vóór uitvoering gemeld.","Prijzen zijn exclusief toepasselijke omzetbelasting. Bij grensoverschrijdende B2B-diensten binnen de EU kan met een geldig btw-nummer de verleggingsregeling gelden."]},{heading:"4. Medewerking van de opdrachtgever",paragraphs:["De opdrachtgever stelt content, toegangsgegevens, goedkeuringen, contactpersonen, juridische teksten en vakinhoudelijke beslissingen tijdig beschikbaar. Vertragingen of meerwerk door ontbrekende medewerking kunnen planning en prijs beïnvloeden.","Toegangsgegevens dienen via overeengekomen veilige kanalen te worden verstrekt. Geheimen mogen niet ongevraagd in openbare tickets, chats of repositories worden geplaatst."]},{heading:"5. AI-ondersteunde werkwijze",paragraphs:["NeXify AI zet moderne AI-ondersteunde ontwikkel-, analyse- en controletools in. Deze dienen versnelling en kwaliteitsborging. De vakinhoudelijke verantwoordelijkheid wordt niet aan een AI-systeem overgedragen.","Voor zover de opdrachtgever bijzondere eisen heeft aan verwerking, modelkeuze, datalocatie of geheimhouding, moeten deze vóór projectstart worden gemeld en overeengekomen."]},{heading:"6. Termijnen en leveringstijden",paragraphs:["Op de website genoemde richttijden (bijv. „website in 2–3 werkdagen”) betreffen pure uitvoeringstijd vanaf volledige aanlevering van alle vereiste content en goedkeuringen. Bindende termijnen vereisen uitdrukkelijke overeenkomst.","Overmacht, storingen van derden en aan de opdrachtgever toe te rekenen vertragingen verlengen termijnen in redelijke mate."]},{heading:"7. Acceptatie",paragraphs:["Acceptatieplichtige diensten worden na oplevering getoetst. Wezenlijke gebreken dienen navolgbaar en binnen de overeengekomen of redelijke termijn te worden gemeld. Onwezenlijke afwijkingen staan acceptatie niet in de weg.","Productief gebruik, publicatie of uitblijvende terugkoppeling na een redelijke toetsingsperiode kan als acceptatie gelden, voor zover dit in de concrete overeenkomst toelaatbaar en aangekondigd is."]},{heading:"8. Gebruiksrechten en open source",paragraphs:["Na volledige betaling verkrijgt de opdrachtgever de overeengekomen gebruiksrechten op het individueel gemaakte werk. Reeds bestaande tools, generieke componenten, frameworks, methoden en knowhow blijven bij hun respectieve rechthebbenden resp. NeXify AI.","Open-source-componenten en diensten van derden vallen onder hun eigen licentie- en gebruiksvoorwaarden. Deze worden niet door de projectovereenkomst vervangen."]},{heading:"9. Derden en doorlopende kosten",paragraphs:["Hosting, domeinen, betaalproviders, app-stores, externe API's, AI-model-gebruikskosten, licenties, transactie- en gebruikskosten zijn alleen inbegrepen indien uitdrukkelijk overeengekomen. Wijzigingen, storingen of beperkingen van derden liggen buiten de directe invloed van NeXify AI."]},{heading:"10. Garantie en aansprakelijkheid",paragraphs:["NeXify AI herstelt reproduceerbare gebreken binnen een redelijke termijn. Geen softwareproduct is onder alle denkbare omstandigheden volledig foutloos; verschuldigd is de overeengekomen kwaliteit en vakkundige uitvoering.","Onbeperkte aansprakelijkheid geldt bij opzet, grove nalatigheid, letsel aan leven, lichaam of gezondheid en dwingende wettelijke aansprakelijkheid. Bij licht nalatige schending van wezenlijke contractuele verplichtingen is de aansprakelijkheid beperkt tot de contracttypisch voorzienbare schade; overigens is aansprakelijkheid voor lichte nalatigheid uitgesloten.","Voor gegevensverlies is NeXify AI slechts aansprakelijk in de omvang die ook bij correcte, regelmatige back-ups door de opdrachtgever zou zijn opgetreden."]},{heading:"11. Betaling",paragraphs:["Facturen zijn binnen de vermelde termijn zonder aftrek betaalbaar. Bij grotere projecten kunnen termijnbetalingen, vooruitbetalingen of milestone-betalingen worden overeengekomen.","Bij betalingsverzuim gelden de wettelijke B2B-gevolgen inclusief vertragingsrente en redelijke incasso- resp. proceskosten. NeXify AI kan diensten bij aanzienlijke betalingsachterstand na aankondiging opschorten."]},{heading:"12. Vertrouwelijkheid en gegevensbescherming",paragraphs:["Beide partijen behandelen niet-openbare bedrijfs- en projectgegevens vertrouwelijk. De vertrouwelijkheid blijft na het einde van de overeenkomst voortbestaan.","Voor zover NeXify AI persoonsgegevens in opdracht verwerkt, wordt een verwerkersovereenkomst conform art. 28 AVG gesloten (zie pagina „Verwerkersovereenkomst”)."]},{heading:"13. Referentievermelding",paragraphs:["NeXify AI mag de opdrachtgever na projectafronding met naam en logo als referentie vermelden, tenzij de opdrachtgever hiertegen bezwaar maakt of iets anders is overeengekomen. Vertrouwelijke projectdetails worden daarbij niet openbaar gemaakt."]},{heading:"14. Looptijd, opzegging en projectonderbreking",paragraphs:["Projectovereenkomsten eindigen met de levering van de overeengekomen dienst. Doorlopende diensten kunnen conform de overeengekomen termijnen worden opgezegd. Het recht op buitengewone opzegging blijft bestaan.","Bij onderbreking vanuit de verantwoordelijkheidssfeer van de opdrachtgever worden reeds geleverde diensten gefactureerd; een latere hervatting kan opnieuw worden ingepland."]},{heading:"15. Recht, bevoegde rechter en slotbepalingen",paragraphs:["Nederlands recht is van toepassing met uitsluiting van het Weens Koopverdrag en conflictenrechtelijke verwijzingen, voor zover geen dwingende bepalingen zich daartegen verzetten. Bevoegde rechter voor B2B-opdrachtgevers is de vestigingsplaats van NeXify AI, voor zover toelaatbaar.","Indien afzonderlijke bepalingen ongeldig zijn, blijft de geldigheid van de overige bepalingen onaangetast. In plaats van de ongeldige bepaling geldt de wettelijk toelaatbare regeling die het economische doel het dichtst benadert."]}]},"ki-hinweise":{slug:"ki-hinweise",title:"AI-verklaring",intro:"Hoe NeXify AI moderne AI-tools inzet – transparant uitgelegd, inclusief de NeXify AI adviseur op deze website.",updated:"Juni 2026",sections:[{heading:"AI-ondersteund in plaats van AI-uitbesteed",paragraphs:["NeXify AI gebruikt AI-tools voor onderzoek, structurering, concepten, ontwikkelingsondersteuning, tests, vertalingen en documentatie. Deze tools versnellen werkstappen, maar vervangen geen vakinhoudelijke verantwoordelijkheid, controle en goedkeuring."]},{heading:"De NeXify AI adviseur op deze website",paragraphs:["NeXify AI is een AI-ondersteunde advies- en salesassistent. Hij beantwoordt vragen over diensten en prijzen, kwalificeert aanvragen en kan op uitdrukkelijk verzoek een vrijblijvende offerte opstellen en per e-mail versturen.","U communiceert daarbij met een geautomatiseerd systeem, niet met een mens. Alle door NeXify AI opgestelde offertes zijn vrijblijvende indicaties; bindende offertes worden uitsluitend door Pascal Courbois persoonlijk getoetst en bevestigd.","De assistent beschikt over een geheugenfunctie: kerninhouden van gesprekken kunnen worden opgeslagen, zodat u bij een volgend contact niet opnieuw hoeft te beginnen. Daarnaast kunnen e-mails aan mail@nexifyai.cloud AI-ondersteund worden voorgesorteerd en beantwoord. Details en bezwaarmogelijkheden vindt u in de privacyverklaring.","De AI-adviseur kan fouten maken. Bij onduidelijkheden of belangrijke beslissingen kunt u ons het beste rechtstreeks per e-mail of telefoon benaderen."]},{heading:"Menselijke controle",bullets:["Doelen, architectuur en vakinhoudelijke beslissingen worden gestuurd door een verantwoordelijke vakman.","AI-uitvoer wordt getoetst op plausibiliteit, veiligheid, projectcontext en kwaliteit.","Juridische, fiscale, medische of andere hoogrisico-beslissingen worden niet uitsluitend op AI-uitvoer gebaseerd.","Productieve wijzigingen worden conform het overeengekomen risico getest en gedocumenteerd.","Automatisch gegenereerde offertes worden vóór contractsluiting altijd menselijk getoetst."]},{heading:"Data en vertrouwelijkheid",paragraphs:["Vertrouwelijke gegevens of persoonsgegevens worden alleen in de vereiste omvang verwerkt. Model-, hosting- en dataverwerkingsroutes worden passend bij het project gekozen. Klantgegevens worden niet bewust vrijgegeven voor algemene modeltraining, tenzij uitdrukkelijk overeengekomen en wettelijk toegestaan.","Details over de gegevensverwerking in de chat vindt u in de privacyverklaring, sectie „NeXify AI adviseur”."]},{heading:"EU AI Act en transparantie",paragraphs:["NeXify AI volgt de vereisten van de EU-AI-verordening (AI Act) en implementeert de transparantieverplichtingen: gebruikers worden geïnformeerd wanneer zij met een AI-systeem communiceren, en AI-gegenereerde offerte-indicaties worden als zodanig gemarkeerd.","Bij klantprojecten met AI-componenten adviseren wij over risicoclassificatie en de telkens geldende verplichtingen."]},{heading:"Grenzen",paragraphs:["AI-systemen kunnen onvolledige, verouderde of onjuiste resultaten genereren. NeXify AI beperkt dit risico door bronnencontrole, tests, review, beperkte rechten en navolgbare werkstanden. Absolute foutloosheid kan niet worden gegarandeerd."]}]},"cookie-richtlinie":{slug:"cookie-richtlinie",title:"Cookie- en opslagbeleid",intro:"Deze website is ingericht op datazuinig gebruik zonder standaard marketing-tracking.",updated:"Juni 2026",sections:[{heading:"Noodzakelijke opslagtechnieken",paragraphs:["Technisch noodzakelijke cookies of lokale opslag (localStorage) kunnen worden ingezet om veiligheid, formulierstatussen, uw taalkeuze (Duits/Nederlands), de status van de chatassistent of elementaire websitefuncties aan te bieden. Zij dienen niet voor gedragsgerichte reclame."]},{heading:"Concreet ingezette opslag",bullets:["nexify-lang (localStorage): slaat uw taalkeuze DE/NL op – tot verwijdering door u.","nova-greeted (localStorage): onthoudt dat de chatassistent zich al heeft voorgesteld, om herhaald automatisch openen te voorkomen.","nexify-consent (localStorage): slaat uw keuze in de cookiebanner op (categorieën en tijdstip van de beslissing) – tot verwijdering of wijziging door u.","Sessie-ID van de chat: technische koppeling van uw gespreksverloop tijdens het gebruik.","Inlogcookie van het klantportaal (HttpOnly): houdt uw sessie na het inloggen in stand; technisch noodzakelijk voor het portaal."]},{heading:"Uw cookie-instellingen (toestemmingsbeheer)",paragraphs:["Bij uw eerste bezoek aan deze website kunt u via de cookiebanner kiezen welke categorieën u toestaat: „Noodzakelijk” (altijd actief), „Statistiek” en „Marketing”. Uw beslissing wordt uitsluitend lokaal in uw browser opgeslagen (nexify-consent) en niet aan derden doorgegeven.","De categorieën Statistiek en Marketing staan standaard uit (opt-in in de zin van art. 6 lid 1 sub a AVG en art. 11.7a Telecommunicatiewet). Zolang u geen toestemming geeft, worden geen bijbehorende diensten geladen. Momenteel zet deze website in beide categorieën geen diensten in; zij zijn bedoeld voor mogelijke toekomstige uitbreidingen en zouden vóór activering hier transparant worden benoemd.","U kunt uw keuze op elk moment met werking voor de toekomst wijzigen of intrekken: via de link „Cookie-instellingen” in de voettekst van elke pagina."]},{heading:"Geen standaard marketing-cookies",paragraphs:["Zonder afzonderlijke aankondiging en toestemming worden geen niet-noodzakelijke advertentie-, retargeting- of platformoverstijgende tracking-cookies geplaatst. Wordt de website in de toekomst met dergelijke diensten uitgebreid, dan worden informatie en toestemmingsmechanisme vóór activering aangepast."]},{heading:"Diensten van derden",paragraphs:["Voor de levering van de website kunnen CDN- en beschermingsdiensten (bijv. Cloudflare) technisch noodzakelijke cookies plaatsen die uitsluitend de veiligheid en lastverdeling dienen."]},{heading:"Browserinstellingen",paragraphs:["U kunt cookies en lokale opslag via uw browser inzien, verwijderen of blokkeren. Bij technisch noodzakelijke opslag kunnen afzonderlijke functies (bijv. de taalkeuze) daardoor beperkt zijn."]}]},avv:{slug:"avv",title:"Verwerkersovereenkomst",intro:"Uitgangspunten voor projecten waarin NeXify AI persoonsgegevens in opdracht van een klant verwerkt (art. 28 AVG).",updated:"Juni 2026",sections:[{heading:"Wanneer een verwerkersovereenkomst vereist is",paragraphs:["Een verwerkersovereenkomst wordt gesloten wanneer NeXify AI persoonsgegevens uitsluitend volgens gedocumenteerde instructie van de klant verwerkt en aan de wettelijke voorwaarden van verwerking in opdracht is voldaan – bijvoorbeeld bij het beheer van web-apps, shops of automatiseringen met klantgegevens."]},{heading:"Typische onderdelen",bullets:["Onderwerp, duur, aard en doel van de verwerking","Categorieën betrokkenen en persoonsgegevens","Instructie- en ondersteuningsprocessen","Vertrouwelijkheidsverplichtingen van de ingezette personen","Technische en organisatorische maatregelen (TOM)","Regels voor subverwerkers en hun goedkeuring","Ondersteuning bij rechten van betrokkenen en DPIA's","Verwijdering, teruggave en bewijsvoering na contracteinde","Meld- en ondersteuningsplichten bij datalekken","Controle- en auditrechten van de verwerkingsverantwoordelijke"]},{heading:"Typische subverwerkers",paragraphs:["Afhankelijk van het project kunnen met name de volgende categorieën subverwerkers worden ingezet: hosting- en cloudinfrastructuur (bijv. Vercel, Hetzner, EU-datacenters), databasediensten (bijv. Supabase), e-mailverzenddiensten (bijv. Resend), CDN- en beveiligingsdiensten (bijv. Cloudflare) en – bij AI-functies – aanbieders van AI-taalmodellen.","De concrete, projectgebonden lijst wordt in de betreffende verwerkersovereenkomst gedocumenteerd en actueel gehouden."]},{heading:"Technische en organisatorische maatregelen",bullets:["Transportversleuteling (TLS) voor alle gegevensoverdrachten","Toegangscontrole volgens het least-privilege-principe","Gescheiden omgevingen voor ontwikkeling, test en productie","Logging van veiligheidsrelevante gebeurtenissen","Regelmatige updates en security-patches","Dataminimalisatie en pseudonimisering waar mogelijk"]},{heading:"Projectgebonden versie",paragraphs:["Aangezien datatypen, systemen, hosting, subverwerkers en risico's per project verschillen, wordt de verwerkersovereenkomst projectgebonden opgesteld of aangevuld. Een actueel sjabloon en de bijbehorende technische en organisatorische maatregelen worden bij de opdracht ter beschikking gesteld."]}]},widerruf:{slug:"widerruf",title:"Informatie over herroepingsrecht",intro:"NeXify AI biedt diensten uitsluitend aan in het zakelijke verkeer (B2B).",updated:"Juni 2026",sections:[{heading:"Geen consumentenovereenkomst",paragraphs:["Overeenkomsten worden uitsluitend gesloten met ondernemers, rechtspersonen en vergelijkbare organisaties die handelen in de uitoefening van hun bedrijf of zelfstandig beroep. Het wettelijke herroepingsrecht voor consumenten bij overeenkomsten op afstand is daarom in principe niet van toepassing.","Met aanvraag en opdrachtverlening bevestigt de opdrachtgever als ondernemer in de zin van het toepasselijke recht te handelen."]},{heading:"Uitzonderingsgevallen",paragraphs:["Mocht in een uitzonderingsgeval een persoon in strijd met deze oriëntatie als consument willen handelen, dan moet dit vóór contractsluiting uitdrukkelijk worden gemeld en afzonderlijk worden overeengekomen. In dat geval worden de wettelijke informatieplichten en herroepingsinstructies individueel verstrekt – of wordt de contractsluiting geweigerd."]},{heading:"Coulance bij projectannulering",paragraphs:["Ongeacht het ontbrekende wettelijke herroepingsrecht geldt: vóór aanvang van de uitvoering kan een verstrekte opdracht schriftelijk kosteloos worden geannuleerd, mits nog geen diensten zijn geleverd. Reeds geleverde concept- of uitvoeringsdiensten worden naar rato van het dagtarief gefactureerd."]}]}};var b=e.i(63125);let k={de:"Rechtliches",nl:"Juridisch",en:"Legal"},v={de:"Stand",nl:"Laatst bijgewerkt",en:"Last updated"};function p({page:e,lang:r="de"}){return(0,n.jsx)("main",{className:"pb-10 pt-28 md:pt-36","data-testid":`legal-page-${e.slug}`,children:(0,n.jsx)("div",{className:"site-container",children:(0,n.jsxs)("div",{className:"max-w-3xl",children:[(0,n.jsx)("span",{className:"eyebrow",children:k[r]}),(0,n.jsx)("h1",{className:"mt-4 font-[family-name:var(--font-heading)] text-4xl font-light tracking-tight text-white sm:text-5xl",children:e.title}),(0,n.jsx)("p",{className:"mt-5 text-lg leading-relaxed text-zinc-400",children:e.intro}),(0,n.jsxs)("p",{className:"mt-3 text-xs uppercase tracking-[0.2em] text-zinc-600",children:[v[r],": ",e.updated]}),(0,n.jsx)("div",{className:"mt-12 space-y-10",children:e.sections.map((e,r)=>(0,n.jsxs)("section",{children:[(0,n.jsx)("h2",{className:"font-[family-name:var(--font-heading)] text-xl font-medium text-white",children:e.heading}),e.paragraphs?.map((e,r)=>(0,n.jsx)("p",{className:"mt-3 text-[15px] leading-[1.85] text-zinc-400",children:e},r)),e.bullets&&(0,n.jsx)("ul",{className:"mt-3 space-y-2",children:e.bullets.map((e,r)=>(0,n.jsxs)("li",{className:"flex gap-3 text-[15px] leading-relaxed text-zinc-400",children:[(0,n.jsx)("span",{className:"mt-[9px] block size-1 shrink-0 rounded-full bg-zinc-500"}),e]},r))})]},r))})]})})})}e.s(["LegalPage",0,p,"LegalPageView",0,function({slug:e}){let{lang:r}=(0,b.useLang)(),i=("nl"===r?c:d)[e];return i?(0,n.jsx)(p,{page:i,lang:"nl"===r?"nl":"de"}):null}],84116)}]);